// Only ever pulls from vehicle_sightings/person_sightings (via ingest-worker's
// /sightings/* API) -- rows only exist there once a raw event was cropped and analyzed
// by the VLM, so the agent can only ever answer from genuinely analyzed events.
const isReal = (o) => o && Object.keys(o).length > 0;

// Defensive against either shape an HTTP node can produce for a JSON-array response: one item
// per array element (most n8n versions auto-split this), or one item whose json IS the array.
function collectRows(nodeName) {
  const items = $(nodeName).all();
  if (items.length === 1 && Array.isArray(items[0].json)) {
    return items[0].json.filter(isReal);
  }
  return items.map((i) => i.json).filter(isReal);
}

const cars = collectRows('Query Recent Car Sightings (API)');
const persons = collectRows('Query Recent Person Sightings (API)');

const webhookJson = $('Ask Webhook').first().json;
const body = webhookJson.body ?? webhookJson;
const question = (body.question ?? '').toString().trim();

function fmtTime(ts) {
  return new Date(ts).toLocaleString('en-GB', { timeZone: 'UTC' }) + ' UTC';
}

const carLines = cars.map((c) => `- ${fmtTime(c.start_ts)} camera=${c.camera} color=${c.color ?? '?'} body=${c.body_type ?? '?'} make=${c.make_guess ?? '?'} plate=${c.plate_text_llm || c.plate_text_frigate || '?'}`);
const personLines = persons.map((p) => `- ${fmtTime(p.start_ts)} camera=${p.camera} description="${p.description}"`);

const context = [
  `Vehicle sightings (${cars.length}, most recent first):`,
  ...(carLines.length ? carLines : ['(none)']),
  '',
  `Person sightings (${persons.length}, most recent first):`,
  ...(personLines.length ? personLines : ['(none)']),
].join('\n');

return [{ json: { question, context } }];

